import { Component, Input } from '@angular/core';

@Component({
   selector: 'app-footer',
   templateUrl: './footer.component.html',
   styleUrls: ['./footer.component.css']
})
export class FooterComponent {

  @Input() appTitle = ''
   public date: any;
   public year = Number;

   ngOnInit() {
      this.date = new Date()
      this.year = this.date.getFullYear();
   }
}
